-      CallChecker = CompChecker;
+        auto AbsChecker = [&](unsigned BitWidth, unsigned OrigBitWidth) {
+          // For abs, we can demote if abs(x) fits in BitWidth bits.
+          // That is, -2^BitWidth < x < 2^BitWidth.
+          return all_of(E.Scalars, [&](Value *V) {
+            auto *I = cast<Instruction>(V);
+            Value *Op = I->getOperand(0);
+            // Check if abs(Op) fits in BitWidth bits.
+            // We need to check both positive and negative ranges.
+            APInt MaxPos = APInt::getSignedMaxValue(BitWidth).zext(OrigBitWidth);
+            APInt MinNeg = APInt::getSignedMinValue(BitWidth).sext(OrigBitWidth);
+            // For negative values, we need -value to fit in BitWidth bits.
+            // Actually, we need: MinNeg <= Op <= MaxPos
+            // But checking this precisely is complex. For now,
+            // conservatively disallow demotion unless we can prove
+            // the value is small enough.
+            // TODO: Implement proper range checking.
+            return false;
+          });
+        };
+        if (ID == Intrinsic::abs) {
+          CallChecker = AbsChecker;
+        } else {
+          Operands.push_back(getOperandEntry(&E, 1));
+          CallChecker = CompChecker;
+        }
     }
     InstructionCost BestCost =
         std::numeric_limits<InstructionCost::CostType>::max();
